mapper.select:
SELECT content_id, tenant_id, content_nm, content_type, content_url, content_desc, duration_minutes, use_yn, reg_dt, upd_dt FROM tb_content WHERE 1=1
AND tenant_id = #{tenantId}
AND use_yn = #{useYn}
ORDER BY reg_dt DESC

mapper.delete:
UPDATE tb_content
SET use_yn = 'N',
    upd_dt = NOW()
WHERE content_id = #{contentId}
AND tenant_id = #{tenantId}

